            '// Example: Error Handling in Gno\n//\n// This example demonstrates effective error handling patterns in Gno.\n\npackage language\n\nimport (\n\t"errors"\n\t"fmt"\n\t"strconv"\n)\n\n// Define custom error types\nvar (\n\tErrInvalidAmount     = errors.New("invalid amount: must be positive")\n\tErrInsufficientFunds = errors.New("insufficient funds")\n\tErrUnauthorized      = errors.New("unauthorized operation")\n)\n\n// Define a simple account structure\ntype Account struct {\n\tOwner   string\n\tBalance uint64\n}\n\n// Transfer demonstrates error handling for a token transfer\nfunc (a *Account) Transfer(to *Account, amount uint64, sender string) error {\n\t// First validation: check authorization\n\tif a.Owner != sender {\n\t\treturn fmt.Errorf("transfer failed: %w", ErrUnauthorized)\n\t}\n\n\t// Second validation: verify positive amount\n\tif amount == 0 {\n\t\treturn fmt.Errorf("transfer failed: %w", ErrInvalidAmount)\n\t}\n\n\t// Third validation: check sufficient balance\n\tif a.Balance < amount {\n\t\treturn fmt.Errorf("transfer failed: %w: needed %d, have %d",\n\t\t\tErrInsufficientFunds, amount, a.Balance)\n\t}\n\n\t// Perform the transfer\n\ta.Balance -= amount\n\tto.Balance += amount\n\treturn nil\n}\n\n// Deposit demonstrates basic validation with error handling\nfunc (a *Account) Deposit(amount uint64) error {\n\tif amount == 0 {\n\t\treturn ErrInvalidAmount\n\t}\n\n\ta.Balance += amount\n\treturn nil\n}\n\n// FormatError demonstrates how to process errors for user-friendly messages\nfunc FormatError(err error) string {\n\tif err == nil {\n\t\treturn "Operation successful"\n\t}\n\n\t// Check for specific error types using errors.Is\n\tif errors.Is(err, ErrInvalidAmount) {\n\t\treturn "Error: Please provide a valid positive amount"\n\t}\n\n\tif errors.Is(err, ErrInsufficientFunds) {\n\t\treturn "Error: Your account does not have enough funds"\n\t}\n\n\tif errors.Is(err, ErrUnauthorized) {\n\t\treturn "Error: You don\'t have permission to perform this action"\n\t}\n\n\t// Return the raw error message for unexpected errors\n\treturn fmt.Sprintf("Unexpected error: %s", err.Error())\n}\n\n// ExecuteTransfer demonstrates handling errors from function calls\nfunc ExecuteTransfer(from *Account, to *Account, amount uint64, sender string) string {\n\terr := from.Transfer(to, amount, sender)\n\tif err != nil {\n\t\treturn FormatError(err)\n\t}\n\n\treturn fmt.Sprintf("Successfully transferred %d tokens from %s to %s",\n\t\tamount, from.Owner, to.Owner)\n}\n\n// Demo function to showcase error handling\nfunc DemoErrors() string {\n\talice := &Account{Owner: "alice", Balance: 100}\n\tbob := &Account{Owner: "bob", Balance: 50}\n\n\toutput := "=== Error Handling Example ===\\n\\n"\n\n\t// Successful transfer\n\toutput += "Attempt 1: Alice sends 20 tokens to Bob\\n"\n\toutput += ExecuteTransfer(alice, bob, 20, "alice") + "\\n\\n"\n\n\t// Insufficient funds\n\toutput += "Attempt 2: Alice tries to send 200 tokens to Bob\\n"\n\toutput += ExecuteTransfer(alice, bob, 200, "alice") + "\\n\\n"\n\n\t// Invalid amount\n\toutput += "Attempt 3: Alice tries to send 0 tokens to Bob\\n"\n\toutput += ExecuteTransfer(alice, bob, 0, "alice") + "\\n\\n"\n\n\t// Unauthorized transfer\n\toutput += "Attempt 4: Eve tries to send from Alice\'s account\\n"\n\toutput += ExecuteTransfer(alice, bob, 10, "eve") + "\\n"\n\n\treturn output\n}\n',
