        module: 'language',
        code: '// Example: Interfaces in Gno\n//\n// This example demonstrates how to define and implement interfaces in Gno.\n\npackage language\n\nimport (\n\t"fmt"\n\t"strconv"\n)\n\n// Define an interface named Shape\n// Interfaces in Gno work similar to Go interfaces - they define a set of method signatures\ntype Shape interface {\n\tArea() float64\n\tPerimeter() float64\n\tDescription() string\n}\n\n// Rectangle implements the Shape interface\ntype Rectangle struct {\n\tWidth  float64\n\tHeight float64\n}\n\n// Area calculates the area of a rectangle\nfunc (r Rectangle) Area() float64 {\n\treturn r.Width * r.Height\n}\n\n// Perimeter calculates the perimeter of a rectangle\nfunc (r Rectangle) Perimeter() float64 {\n\treturn 2 * (r.Width + r.Height)\n}\n\n// Description returns a string representation of the rectangle\nfunc (r Rectangle) Description() string {\n\treturn fmt.Sprintf("Rectangle(width: %.2f, height: %.2f)", r.Width, r.Height)\n}\n\n// Circle implements the Shape interface\ntype Circle struct {\n\tRadius float64\n}\n\n// Area calculates the area of a circle\nfunc (c Circle) Area() float64 {\n\treturn 3.14159 * c.Radius * c.Radius\n}\n\n// Perimeter calculates the circumference of a circle\nfunc (c Circle) Perimeter() float64 {\n\treturn 2 * 3.14159 * c.Radius\n}\n\n// Description returns a string representation of the circle\nfunc (c Circle) Description() string {\n\treturn fmt.Sprintf("Circle(radius: %.2f)", c.Radius)\n}\n\n// ShapeInfo processes any Shape implementation\n// This demonstrates polymorphism through interfaces\nfunc ShapeInfo(s Shape) string {\n\treturn fmt.Sprintf(\n\t\t"%s\\nArea: %.2f\\nPerimeter: %.2f\\n",\n\t\ts.Description(),\n\t\ts.Area(),\n\t\ts.Perimeter(),\n\t)\n}\n\n// In Gno, interfaces can also be used for type assertions\nfunc PrintShapeDetails(s Shape) string {\n\tresult := ShapeInfo(s)\n\n\t// Type assertions work just like in Go\n\tif rect, ok := s.(Rectangle); ok {\n\t\tresult += fmt.Sprintf("This is a rectangle with aspect ratio: %.2f\\n", rect.Width/rect.Height)\n\t}\n\n\tif circle, ok := s.(Circle); ok {\n\t\tresult += fmt.Sprintf("This is a circle with diameter: %.2f\\n", circle.Radius*2)\n\t}\n\n\treturn result\n}\n\n// Demo function to showcase interface usage\nfunc Demo() string {\n\trect := Rectangle{Width: 5.0, Height: 3.0}\n\tcircle := Circle{Radius: 4.0}\n\n\toutput := "=== Interface Example ===\\n\\n"\n\toutput += PrintShapeDetails(rect) + "\\n"\n\toutput += PrintShapeDetails(circle)\n\n\treturn output\n}\n',
