        title: 'Persistency',
        description: 'Demonstrates working with persistent data using AVL trees in Gno realms',
        file: 'r/gnostudio/advanced/persistency.gno',
        namespace: 'r',
        namespaceGroup: 'gnostudio',
        module: 'advanced',
        code: '// Persistency Example\n// Demonstrates working with persistent data using AVL trees in Gno.\n\npackage persistency\n\nimport (\n\t"strconv"\n\n\t"gno.land/p/nt/avl"\n)\n\n// Persistent AVL tree that persists across transactions\nvar counter = avl.NewTree()\n\n// Initialize counter\nfunc init() {\n\tcounter.Set("count", 0)\n}\n\n// Increment the counter and return the new value\nfunc incrementCounter() int {\n\tcount := counter.Get("count").(int)\n\tcount++\n\tcounter.Set("count", count)\n\treturn count\n}\n\n// Reset the counter to zero\nfunc ResetCounter() {\n\tcounter.Set("count", 0)\n}\n\n// Render the current counter value\nfunc Render(path string) string {\n\tcount := incrementCounter()\n\treturn "Counter has been viewed " + strconv.Itoa(count) + " times"\n}\n',
