        title: 'User Registry',
        description: 'User registration and management system',
        file: 'r/demo/userbook/userbook.gno',
        namespace: 'r',
        namespaceGroup: 'demo',
        module: 'userbook',
        code: '// Official Example from gnolang/gno\n// Source: https://github.com/gnolang/gno/tree/master/examples/gno.land/r/demo/userbook\n\n// Package userbook demonstrates a small userbook system working with gnoweb\npackage userbook\n\nimport (\n\t"chain"\n\t"chain/runtime"\n\t"time"\n\n\t"gno.land/p/nt/avl"\n\t"gno.land/p/nt/seqid"\n\t"gno.land/p/nt/ufmt"\n)\n\ntype Signup struct {\n\taddress_XXX address\n\tordinal     int\n\ttimestamp   time.Time\n}\n\nvar (\n\tsignupsTree = avl.NewTree()\n\ttracker     = avl.NewTree()\n\tidCounter   seqid.ID\n)\n\nconst signUpEvent = "SignUp"\n\nfunc init() {\n\tSignUp(cross) // Sign up the deployer\n}\n\nfunc SignUp(cur realm) string {\n\t// Get transaction caller\n\tcaller := runtime.PreviousRealm().Address()\n\n\t// Check if the user is already signed up\n\tif _, exists := tracker.Get(caller.String()); exists {\n\t\tpanic(caller.String() + " is already signed up!")\n\t}\n\n\tnow := time.Now()\n\n\t// Sign up the user\n\tsignupsTree.Set(idCounter.Next().String(), &Signup{\n\t\tcaller,\n\t\tsignupsTree.Size(),\n\t\tnow,\n\t})\n\n\ttracker.Set(caller.String(), struct{}{})\n\n\tchain.Emit(signUpEvent, "account", caller.String())\n\n\treturn ufmt.Sprintf("%s added to userbook! Timestamp: %s", caller.String(), now.Format(time.RFC822Z))\n}\n',
        isMultiFile: false,
        files: {
          'userbook.gno':
            '// Official Example from gnolang/gno\n// Source: https://github.com/gnolang/gno/tree/master/examples/gno.land/r/demo/userbook\n\n// Package userbook demonstrates a small userbook system working with gnoweb\npackage userbook\n\nimport (\n\t"chain"\n\t"chain/runtime"\n\t"time"\n\n\t"gno.land/p/nt/avl"\n\t"gno.land/p/nt/seqid"\n\t"gno.land/p/nt/ufmt"\n)\n\ntype Signup struct {\n\taddress_XXX address\n\tordinal     int\n\ttimestamp   time.Time\n}\n\nvar (\n\tsignupsTree = avl.NewTree()\n\ttracker     = avl.NewTree()\n\tidCounter   seqid.ID\n)\n\nconst signUpEvent = "SignUp"\n\nfunc init() {\n\tSignUp(cross) // Sign up the deployer\n}\n\nfunc SignUp(cur realm) string {\n\t// Get transaction caller\n\tcaller := runtime.PreviousRealm().Address()\n\n\t// Check if the user is already signed up\n\tif _, exists := tracker.Get(caller.String()); exists {\n\t\tpanic(caller.String() + " is already signed up!")\n\t}\n\n\tnow := time.Now()\n\n\t// Sign up the user\n\tsignupsTree.Set(idCounter.Next().String(), &Signup{\n\t\tcaller,\n\t\tsignupsTree.Size(),\n\t\tnow,\n\t})\n\n\ttracker.Set(caller.String(), struct{}{})\n\n\tchain.Emit(signUpEvent, "account", caller.String())\n\n\treturn ufmt.Sprintf("%s added to userbook! Timestamp: %s", caller.String(), now.Format(time.RFC822Z))\n}\n',
        },
        mainFile: 'userbook.gno',
        source: 'gno',
